import React, { useState, useRef, useMemo } from 'react';

const theme = {
  bg: '#0a0a0a',
  surface: '#111111',
  surfaceAlt: '#1a1a1a',
  border: '#2a2a2a',
  text: '#fafafa',
  muted: '#a1a1aa',
  dim: '#71717a',
  blue: '#38bdf8',
  pink: '#f472b6',
  green: '#a3e635',
  orange: '#fb923c',
  purple: '#8b5cf6',
};

function klDiv(mupx, mupy, spx, spy, muqx, muqy, sqx, sqy) {
  const logDet = 2 * Math.log((sqx * sqy) / (spx * spy));
  const mahal = ((mupx - muqx) ** 2) / (sqx ** 2) + ((mupy - muqy) ** 2) / (sqy ** 2);
  const tr = (spx ** 2) / (sqx ** 2) + (spy ** 2) / (sqy ** 2);
  const kl = 0.5 * (logDet - 2 + mahal + tr);
  return { kl, logDet, mahal, tr };
}

export default function App() {
  const svgRef = useRef(null);
  const [pMean, setPMean] = useState([1.5, 0.6]);
  const [pScale, setPScale] = useState(1.0);
  const [flipped, setFlipped] = useState(false);
  const [dragging, setDragging] = useState(false);

  const W = 520, H = 260;
  const SVG_CX = W / 2, SVG_CY = H / 2;
  const SCALE = 52;

  const qMeanV = [0, 0];
  const qSigX = 1.4, qSigY = 1.0;
  const pSigX = 1.0 * pScale, pSigY = 0.7 * pScale;

  const toSVG = (x, y) => [SVG_CX + x * SCALE, SVG_CY - y * SCALE];
  const fromSVG = (sx, sy) => [(sx - SVG_CX) / SCALE, -(sy - SVG_CY) / SCALE];

  const pSVGPos = toSVG(pMean[0], pMean[1]);
  const qSVGPos = toSVG(qMeanV[0], qMeanV[1]);

  const { kl, logDet, mahal, tr } = useMemo(() => {
    if (!flipped) {
      return klDiv(pMean[0], pMean[1], pSigX, pSigY, qMeanV[0], qMeanV[1], qSigX, qSigY);
    } else {
      return klDiv(qMeanV[0], qMeanV[1], qSigX, qSigY, pMean[0], pMean[1], pSigX, pSigY);
    }
  }, [pMean, pSigX, pSigY, flipped]);

  const handlePointerMove = (clientX, clientY) => {
    if (!dragging) return;
    const rect = svgRef.current.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const sx = (clientX - rect.left) * scaleX;
    const sy = (clientY - rect.top) * scaleY;
    const [x, y] = fromSVG(sx, sy);
    setPMean([Math.max(-4.2, Math.min(4.2, x)), Math.max(-2.2, Math.min(2.2, y))]);
  };

  const pColor = flipped ? theme.pink : theme.blue;
  const qColor = flipped ? theme.blue : theme.pink;
  const pLabel = flipped ? 'Q' : 'P';
  const qLabel = flipped ? 'P' : 'Q';

  const gridLines = [];
  for (let i = -4; i <= 4; i++) {
    const [ax, ay] = toSVG(i, -3);
    const [bx, by] = toSVG(i, 3);
    gridLines.push(<line key={'v' + i} x1={ax} y1={ay} x2={bx} y2={by} stroke={theme.border} strokeWidth={0.5} />);
    const [cx2, cy2] = toSVG(-4, i);
    const [dx, dy] = toSVG(4, i);
    gridLines.push(<line key={'h' + i} x1={cx2} y1={cy2} x2={dx} y2={dy} stroke={theme.border} strokeWidth={0.5} />);
  }

  const klColor = kl < 0.15 ? theme.green : kl < 1.5 ? theme.orange : theme.pink;

  const getInsight = () => {
    if (kl < 0.12) return 'Nearly zero! When P overlaps Q perfectly, no information is lost encoding P with Q.';
    if (mahal > 1.8 && mahal > Math.abs(logDet) + tr - 2) return `Means are far apart (Mahal = ${mahal.toFixed(2)}). The pink distribution is a poor model for the blue one.`;
    if (Math.abs(logDet) > 0.8) return `Spread mismatch (log-det = ${logDet.toFixed(2)}) dominates. Try sliding P spread toward 1.0x to reduce it.`;
    if (flipped) return `Flipped: KL(Q||P) = ${kl.toFixed(3)}. Compare with KL(P||Q) to see asymmetry — KL is NOT symmetric!`;
    return `Drag P (blue) onto Q (pink) to minimize KL. Flip to see KL(Q||P) and discover asymmetry!`;
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: theme.bg,
      color: theme.text,
      fontFamily: "'JetBrains Mono', monospace",
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      padding: '14px 12px',
      boxSizing: 'border-box',
    }}>
      <div style={{ width: '100%', maxWidth: 560 }}>

        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 10 }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700, color: theme.text }}>KL Divergence</div>
            <div style={{ fontSize: 11, color: theme.muted, marginTop: 2 }}>Drag the blue ellipse. Watch KL change.</div>
          </div>
          <button
            onClick={() => setFlipped(f => !f)}
            style={{
              padding: '6px 11px',
              background: flipped ? (theme.orange + '22') : theme.surfaceAlt,
              border: '1px solid ' + (flipped ? theme.orange : theme.border),
              borderRadius: 6,
              color: flipped ? theme.orange : theme.muted,
              fontFamily: "'JetBrains Mono', monospace",
              fontSize: 11,
              cursor: 'pointer',
              transition: 'all 0.2s ease',
            }}
          >
            {flipped ? 'KL(Q||P)' : 'KL(P||Q)'}
          </button>
        </div>

        {/* KL Value banner */}
        <div style={{
          textAlign: 'center',
          marginBottom: 8,
          padding: '8px 12px',
          background: theme.surface,
          borderRadius: 8,
          border: '1px solid ' + theme.border,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: 8,
        }}>
          <span style={{ fontSize: 12, color: theme.muted }}>
            KL({flipped ? 'Q' : 'P'} || {flipped ? 'P' : 'Q'}) =
          </span>
          <span style={{
            fontSize: 26,
            fontWeight: 700,
            color: klColor,
            transition: 'color 0.3s ease',
          }}>
            {kl.toFixed(3)}
          </span>
          <span style={{ fontSize: 11, color: theme.dim }}>
            {kl < 0.12 ? '(min)' : kl > 3 ? '(high)' : ''}
          </span>
        </div>

        {/* Main SVG */}
        <div style={{ background: theme.surface, borderRadius: 10, border: '1px solid ' + theme.border, marginBottom: 8, overflow: 'hidden' }}>
          <svg
            ref={svgRef}
            width="100%"
            viewBox={'0 0 ' + W + ' ' + H}
            style={{ display: 'block', cursor: dragging ? 'grabbing' : 'default', userSelect: 'none' }}
            onMouseMove={e => handlePointerMove(e.clientX, e.clientY)}
            onMouseUp={() => setDragging(false)}
            onMouseLeave={() => setDragging(false)}
            onTouchMove={e => { e.preventDefault(); handlePointerMove(e.touches[0].clientX, e.touches[0].clientY); }}
            onTouchEnd={() => setDragging(false)}
          >
            {gridLines}

            {/* Axes */}
            <line x1={toSVG(-4.5, 0)[0]} y1={toSVG(-4.5, 0)[1]} x2={toSVG(4.5, 0)[0]} y2={toSVG(4.5, 0)[1]} stroke={theme.dim} strokeWidth={1} />
            <line x1={toSVG(0, -3)[0]} y1={toSVG(0, -3)[1]} x2={toSVG(0, 3)[0]} y2={toSVG(0, 3)[1]} stroke={theme.dim} strokeWidth={1} />

            {/* Distance line */}
            <line
              x1={pSVGPos[0]} y1={pSVGPos[1]}
              x2={qSVGPos[0]} y2={qSVGPos[1]}
              stroke={theme.orange}
              strokeWidth={1.5}
              strokeDasharray="4 3"
              strokeOpacity={Math.min(1, mahal * 0.5)}
            />

            {/* Q ellipses (2-sigma dashed, 1-sigma solid) */}
            <ellipse cx={qSVGPos[0]} cy={qSVGPos[1]} rx={qSigX * SCALE * 2} ry={qSigY * SCALE * 2}
              fill="none" stroke={qColor} strokeWidth={1} strokeOpacity={0.25} strokeDasharray="4 3" />
            <ellipse cx={qSVGPos[0]} cy={qSVGPos[1]} rx={qSigX * SCALE} ry={qSigY * SCALE}
              fill={qColor} fillOpacity={0.1} stroke={qColor} strokeWidth={2} strokeOpacity={0.85} />

            {/* Q mean dot */}
            <circle cx={qSVGPos[0]} cy={qSVGPos[1]} r={4} fill={qColor} />
            <text x={qSVGPos[0] + 10} y={qSVGPos[1] - 10} fill={qColor} fontSize={13} fontFamily="monospace" fontWeight={700}>{qLabel}</text>

            {/* P ellipses (draggable) */}
            <ellipse cx={pSVGPos[0]} cy={pSVGPos[1]} rx={pSigX * SCALE * 2} ry={pSigY * SCALE * 2}
              fill="none" stroke={pColor} strokeWidth={1} strokeOpacity={0.25} strokeDasharray="4 3" />
            <ellipse cx={pSVGPos[0]} cy={pSVGPos[1]} rx={pSigX * SCALE} ry={pSigY * SCALE}
              fill={pColor} fillOpacity={0.1} stroke={pColor} strokeWidth={2} strokeOpacity={0.85} />

            {/* P mean handle (draggable) */}
            <circle
              cx={pSVGPos[0]} cy={pSVGPos[1]} r={14}
              fill="transparent"
              style={{ cursor: 'grab' }}
              onMouseDown={e => { e.preventDefault(); setDragging(true); }}
              onTouchStart={e => { e.preventDefault(); setDragging(true); }}
            />
            <circle cx={pSVGPos[0]} cy={pSVGPos[1]} r={5} fill={pColor} style={{ pointerEvents: 'none' }} />
            <circle cx={pSVGPos[0]} cy={pSVGPos[1]} r={10} fill="none" stroke={pColor} strokeWidth={1.5} strokeOpacity={0.45} style={{ pointerEvents: 'none' }} />
            <text x={pSVGPos[0] + 13} y={pSVGPos[1] - 10} fill={pColor} fontSize={13} fontFamily="monospace" fontWeight={700} style={{ pointerEvents: 'none' }}>{pLabel}</text>

            {/* Drag hint */}
            {!dragging && (
              <text x={pSVGPos[0]} y={pSVGPos[1] + 24} textAnchor="middle" fill={pColor} fontSize={9} fillOpacity={0.6} style={{ pointerEvents: 'none' }}>drag me</text>
            )}

            {/* Labels */}
            <text x={toSVG(4.2, 0)[0]} y={toSVG(4.2, 0)[1] + 4} fill={theme.dim} fontSize={10} fontFamily="monospace">x1</text>
            <text x={toSVG(0, 2.7)[0] + 4} y={toSVG(0, 2.7)[1]} fill={theme.dim} fontSize={10} fontFamily="monospace">x2</text>
          </svg>
        </div>

        {/* Slider */}
        <div style={{ marginBottom: 8, padding: '8px 12px', background: theme.surface, borderRadius: 8, border: '1px solid ' + theme.border }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <span style={{ fontSize: 11, color: theme.muted, minWidth: 100 }}>P spread: {pScale.toFixed(1)}x</span>
            <input
              type="range" min={0.3} max={3.0} step={0.1} value={pScale}
              onChange={e => setPScale(parseFloat(e.target.value))}
              style={{ flex: 1, accentColor: theme.blue }}
            />
            <span style={{ fontSize: 11, color: theme.dim, minWidth: 30, textAlign: 'right' }}>
              {pScale < 0.6 ? 'thin' : pScale > 2.2 ? 'wide' : ''}
            </span>
          </div>
        </div>

        {/* Formula breakdown */}
        <div style={{ padding: '10px 12px', background: theme.surface, borderRadius: 8, border: '1px solid ' + theme.border, marginBottom: 8 }}>
          <div style={{ fontSize: 10, color: theme.dim, marginBottom: 8, textAlign: 'center' }}>
            KL = (1/2) * [ log-det  -  p  +  Mahalanobis  +  Trace ]
          </div>
          <div style={{ display: 'flex', gap: 5, justifyContent: 'center', flexWrap: 'wrap' }}>
            {[
              { label: 'log|det|', value: logDet, color: theme.purple },
              { label: '-p = -2', value: -2, color: theme.dim, fixed: true },
              { label: 'Mahal', value: mahal, color: theme.orange },
              { label: 'trace', value: tr, color: theme.green },
            ].map(({ label, value, color, fixed }) => (
              <div key={label} style={{
                textAlign: 'center', padding: '5px 10px',
                background: theme.surfaceAlt, borderRadius: 6, minWidth: 64,
              }}>
                <div style={{ fontSize: 9, color: theme.dim, marginBottom: 2 }}>{label}</div>
                <div style={{ fontSize: 13, color, fontWeight: 600, transition: 'color 0.2s' }}>
                  {fixed ? '-2.00' : value.toFixed(2)}
                </div>
              </div>
            ))}
            <div style={{
              display: 'flex', alignItems: 'center',
              fontSize: 14, color: theme.dim, padding: '0 2px',
            }}>=</div>
            <div style={{
              textAlign: 'center', padding: '5px 12px',
              background: klColor + '18', borderRadius: 6, minWidth: 64,
              border: '1px solid ' + klColor + '44',
            }}>
              <div style={{ fontSize: 9, color: theme.dim, marginBottom: 2 }}>KL</div>
              <div style={{ fontSize: 14, color: klColor, fontWeight: 700, transition: 'color 0.3s' }}>{kl.toFixed(3)}</div>
            </div>
          </div>
        </div>

        {/* Insight */}
        <div style={{
          padding: '10px 14px',
          background: theme.surface,
          borderRadius: 8,
          fontSize: 11,
          color: theme.muted,
          borderLeft: '3px solid ' + klColor,
          lineHeight: 1.6,
          transition: 'border-color 0.3s ease',
        }}>
          <span style={{ color: theme.text, fontWeight: 600 }}>
            {kl < 0.12 ? 'Zero! ' : kl < 0.8 ? 'Low. ' : kl < 2.5 ? 'Moderate. ' : 'High! '}
          </span>
          {getInsight()}
        </div>

      </div>
    </div>
  );
}
